23	namespace ft = fastertransformer;
24	namespace th = torch;
25	namespace torch_ext {
26	
27	using std::vector;
28	
29	class IFGpt {
30	public:
31	    virtual ~IFGpt() {}
32	    virtual void forward(th::Tensor&              input_ids,
33	                         th::Tensor&              input_lengths,
34	                         th::Tensor&              output_ids,
35	                         th::Tensor&              sequence_lengths,
36	                         th::Tensor&              cum_log_probs,
37	                         const size_t             request_output_len,
38	                         const size_t             beam_width,
39	                         th::optional<th::Tensor> top_k_opt,
40	                         th::optional<th::Tensor> top_p_opt,
41	                         th::optional<th::Tensor> beam_search_diversity_rate_opt,
42	                         th::optional<th::Tensor> temperature_opt,
43	                         th::optional<th::Tensor> len_penalty_opt,
44	                         th::optional<th::Tensor> repetition_penalty_opt,
45	                         th::optional<th::Tensor> presence_penalty_opt,
46	                         th::optional<th::Tensor> min_length_opt,
47	                         th::optional<th::Tensor> random_seed_opt,
48	                         th::optional<th::Tensor> bad_words_list_opt,
49	                         th::optional<int64_t>    return_cum_log_probs_opt) = 0;
50	};
51	
52	template<typename T>
53	class FTGpt: public IFGpt {
54	public:
55	    FTGpt(const int64_t              head_num,
56	          const int64_t              size_per_head,
57	          const int64_t              inter_size,
58	          const int64_t              layer_num,
59	          const int64_t              expert_num,
60	          const int64_t              moe_k,
61	          const std::vector<int64_t> moe_layer_index,
62	          const int64_t              vocab_size,
63	          const ft::gptVariantParams gpt_variant_params,
64	          const int64_t              start_id,
65	          const int64_t              end_id,
66	          const int64_t              tensor_para_size,
67	          const int64_t              pipeline_para_size,
68	          const int64_t              int8_mode,
69	          const vector<th::Tensor>   weights,
70	          const vector<th::Tensor>   int8_weights,
71	          const vector<th::Tensor>   scale,
72	          const double               shared_contexts_ratio):
73	        head_num_(head_num),
74	        size_per_head_(size_per_head),
75	        inter_size_(inter_size),
76	        layer_num_(layer_num),
77	        expert_num_(expert_num),
78	        moe_k_(moe_k),
79	        moe_layer_index_(moe_layer_index),
80	        gpt_variant_params_(gpt_variant_params),
81	        vocab_size_(vocab_size),
82	        start_id_(start_id),
83	        end_id_(end_id),
84	        tensor_para_size_(tensor_para_size),
85	        pipeline_para_size_(pipeline_para_size),
86	        int8_mode_(int8_mode),
87	        weights_(weights),
88	        int8_weights_(int8_weights),
89	        scale_(scale),
90	        shared_contexts_ratio_(shared_contexts_ratio)
91	    {
92	        ft::check_cuda_error(cublasLtCreate(&cublasltHandle_));
93	        cublas_algo_map_      = new ft::cublasAlgoMap(GEMM_CONFIG);
94	        cublas_wrapper_mutex_ = new std::mutex();
95	
96	        ftNcclInitialize(tensor_para_, pipeline_para_, tensor_para_size, pipeline_para_size);
97	
98	        gpt_weights_.resizeLayer(layer_num_);
99	        for (int i = 0; i < (int)layer_num_; i++) {
100	            gpt_weights_.decoder_layer_weights[i]->pre_layernorm_weights.gamma =
101	                get_ptr<T>(weights_[i + 0 * layer_num_]);
102	            gpt_weights_.decoder_layer_weights[i]->pre_layernorm_weights.beta =
103	                get_ptr<T>(weights_[i + 1 * layer_num_]);
104	            gpt_weights_.decoder_layer_weights[i]->self_attention_weights.query_weight.kernel =
105	                get_ptr<T>(weights_[i + 2 * layer_num_]);
106	            gpt_weights_.decoder_layer_weights[i]->self_attention_weights.query_weight.bias =
107	                get_ptr<T>(weights_[i + 3 * layer_num_]);
108	            gpt_weights_.decoder_layer_weights[i]->self_attention_weights.attention_output_weight.kernel =
109	                get_ptr<T>(weights_[i + 4 * layer_num_]);
110	            gpt_weights_.decoder_layer_weights[i]->self_attention_weights.attention_output_weight.bias =
111	                get_ptr<T>(weights_[i + 5 * layer_num_]);
112	            gpt_weights_.decoder_layer_weights[i]->self_attn_layernorm_weights.gamma =
113	                get_ptr<T>(weights_[i + 6 * layer_num_]);
114	            gpt_weights_.decoder_layer_weights[i]->self_attn_layernorm_weights.beta =
115	                get_ptr<T>(weights_[i + 7 * layer_num_]);
116	            gpt_weights_.decoder_layer_weights[i]->ffn_weights.intermediate_weight.kernel =
117	                get_ptr<T>(weights_[i + 8 * layer_num_]);
118	            gpt_weights_.decoder_layer_weights[i]->ffn_weights.intermediate_weight.bias =
119	                get_ptr<T>(weights_[i + 9 * layer_num_]);
120	            gpt_weights_.decoder_layer_weights[i]->ffn_weights.output_weight.kernel =
121	                get_ptr<T>(weights_[i + 10 * layer_num_]);
122	            gpt_weights_.decoder_layer_weights[i]->ffn_weights.output_weight.bias =
123	                get_ptr<T>(weights_[i + 11 * layer_num_]);
124	
125	            if (int8_mode_ != 0) {
126	                gpt_weights_.decoder_layer_weights[i]->self_attention_weights.query_weight.int8_kernel =
127	                    get_ptr<int8_t>(int8_weights_[i + 0 * layer_num_]);
128	                gpt_weights_.decoder_layer_weights[i]->self_attention_weights.attention_output_weight.int8_kernel =
129	                    get_ptr<int8_t>(int8_weights_[i + 1 * layer_num_]);
130	                gpt_weights_.decoder_layer_weights[i]->ffn_weights.intermediate_weight.int8_kernel =
131	                    get_ptr<int8_t>(int8_weights_[i + 2 * layer_num_]);
132	                gpt_weights_.decoder_layer_weights[i]->ffn_weights.output_weight.int8_kernel =
133	                    get_ptr<int8_t>(int8_weights_[i + 3 * layer_num_]);
134	
135	                if (int8_mode == 1) {
136	                    gpt_weights_.decoder_layer_weights[i]->self_attention_weights.query_weight.weight_only_quant_scale =
137	                        get_ptr<T>(scale_[i + 0 * layer_num_]);
138	                    gpt_weights_.decoder_layer_weights[i]
139	                        ->self_attention_weights.attention_output_weight.weight_only_quant_scale =
140	                        get_ptr<T>(scale_[i + 1 * layer_num_]);
141	                    gpt_weights_.decoder_layer_weights[i]->ffn_weights.intermediate_weight.weight_only_quant_scale =
142	                        get_ptr<T>(scale_[i + 2 * layer_num_]);
143	                    gpt_weights_.decoder_layer_weights[i]->ffn_weights.output_weight.weight_only_quant_scale =
144	                        get_ptr<T>(scale_[i + 3 * layer_num_]);
145	                }
146	                else {
147	                    gpt_weights_.decoder_layer_weights[i]->self_attention_weights.query_weight.scale =
148	                        get_ptr<float>(scale_[i + 0 * layer_num_]);
149	                    gpt_weights_.decoder_layer_weights[i]->self_attention_weights.attention_output_weight.scale =
150	                        get_ptr<float>(scale_[i + 1 * layer_num_]);
151	                    gpt_weights_.decoder_layer_weights[i]->ffn_weights.intermediate_weight.scale =
152	                        get_ptr<float>(scale_[i + 2 * layer_num_]);
153	                    gpt_weights_.decoder_layer_weights[i]->ffn_weights.output_weight.scale =
154	                        get_ptr<float>(scale_[i + 3 * layer_num_]);
155	                }
156	            }
157	        }
158	
159	        size_t weight_offset = 0;
160	        if (gpt_variant_params_.has_pre_decoder_layernorm) {
161	            gpt_weights_.pre_decoder_layernorm.gamma = get_ptr<T>(weights_[12 * layer_num_ + 0 - weight_offset]);
162	            gpt_weights_.pre_decoder_layernorm.beta  = get_ptr<T>(weights_[12 * layer_num_ + 1 - weight_offset]);
163	        }
164	        else {
165	            weight_offset += 2;
166	        }
167	        if (gpt_variant_params_.has_post_decoder_layernorm) {
168	            gpt_weights_.post_decoder_layernorm.gamma = get_ptr<T>(weights_[12 * layer_num_ + 2 - weight_offset]);
169	            gpt_weights_.post_decoder_layernorm.beta  = get_ptr<T>(weights_[12 * layer_num_ + 3 - weight_offset]);
170	        }
171	        else {
172	            weight_offset += 2;
173	        }
174	        if (gpt_variant_params_.has_positional_encoding) {
175	            gpt_weights_.position_encoding_table = get_ptr<T>(weights_[12 * layer_num_ + 4 - weight_offset]);
176	            gpt_weights_.setMaxSeqLen(weights_[12 * layer_num_ + 4 - weight_offset].size(0));
177	        }
178	        else {
179	            weight_offset += 1;
180	        }
181	        gpt_weights_.pre_decoder_embedding_table   = get_ptr<T>(weights_[12 * layer_num_ + 5 - weight_offset]);
182	        gpt_weights_.post_decoder_embedding.kernel = get_ptr<T>(weights_[12 * layer_num_ + 6 - weight_offset]);
183	
184	        weight_offset = 7 - weight_offset;
185	
186	        for (int i = 0; i < (int)layer_num_; i++) {
187	            if (std::find(moe_layer_index.begin(), moe_layer_index.end(), i) != moe_layer_index.end()) {
188	                gpt_weights_.decoder_layer_weights[i]->ffn_weights.gating_weight.kernel =
189	                    get_ptr<T>(weights_[12 * layer_num_ + weight_offset + i]);
190	            }
191	        }
192	
193	        weight_offset += layer_num_;
194	
195	        if (gpt_variant_params_.has_adapters) {
196	            for (int i = 0; i < (int)layer_num_; i++) {
197	                gpt_weights_.decoder_layer_weights[i]->after_attention_adapter_weights.intermediate_weight.kernel =
198	                    get_ptr<T>(weights_[12 * layer_num_ + weight_offset + i]);
199	                gpt_weights_.decoder_layer_weights[i]->after_attention_adapter_weights.intermediate_weight.bias =
200	                    get_ptr<T>(weights_[13 * layer_num_ + weight_offset + i]);
201	                gpt_weights_.decoder_layer_weights[i]->after_attention_adapter_weights.output_weight.kernel =
202	                    get_ptr<T>(weights_[14 * layer_num_ + weight_offset + i]);
203	                gpt_weights_.decoder_layer_weights[i]->after_attention_adapter_weights.output_weight.bias =
204	                    get_ptr<T>(weights_[15 * layer_num_ + weight_offset + i]);
205	                gpt_weights_.decoder_layer_weights[i]->after_ffn_adapter_weights.intermediate_weight.kernel =
206	                    get_ptr<T>(weights_[16 * layer_num_ + weight_offset + i]);
207	                gpt_weights_.decoder_layer_weights[i]->after_ffn_adapter_weights.intermediate_weight.bias =
208	                    get_ptr<T>(weights_[17 * layer_num_ + weight_offset + i]);
209	                gpt_weights_.decoder_layer_weights[i]->after_ffn_adapter_weights.output_weight.kernel =
210	                    get_ptr<T>(weights_[18 * layer_num_ + weight_offset + i]);
211	                gpt_weights_.decoder_layer_weights[i]->after_ffn_adapter_weights.output_weight.bias =
212	                    get_ptr<T>(weights_[19 * layer_num_ + weight_offset + i]);
213	
214	                if (int8_mode_ != 0) {
215	                    gpt_weights_.decoder_layer_weights[i]
216	                        ->after_attention_adapter_weights.intermediate_weight.int8_kernel =
217	                        get_ptr<int8_t>(int8_weights_[i + 4 * layer_num_]);
218	                    gpt_weights_.decoder_layer_weights[i]->after_attention_adapter_weights.output_weight.int8_kernel =
219	                        get_ptr<int8_t>(int8_weights_[i + 5 * layer_num_]);
220	                    gpt_weights_.decoder_layer_weights[i]->after_ffn_adapter_weights.intermediate_weight.int8_kernel =
221	                        get_ptr<int8_t>(int8_weights_[i + 6 * layer_num_]);
222	                    gpt_weights_.decoder_layer_weights[i]->after_ffn_adapter_weights.output_weight.int8_kernel =
223	                        get_ptr<int8_t>(int8_weights_[i + 7 * layer_num_]);
224	
225	                    if (int8_mode == 1) {
226	                        gpt_weights_.decoder_layer_weights[i]
227	                            ->after_attention_adapter_weights.intermediate_weight.weight_only_quant_scale =
228	                            get_ptr<T>(scale_[i + 4 * layer_num_]);
229	                        gpt_weights_.decoder_layer_weights[i]
230	                            ->after_attention_adapter_weights.output_weight.weight_only_quant_scale =
231	                            get_ptr<T>(scale_[i + 5 * layer_num_]);
232	                        gpt_weights_.decoder_layer_weights[i]
233	                            ->after_ffn_adapter_weights.intermediate_weight.weight_only_quant_scale =
234	                            get_ptr<T>(scale_[i + 6 * layer_num_]);
235	                        gpt_weights_.decoder_layer_weights[i]
236	                            ->after_ffn_adapter_weights.output_weight.weight_only_quant_scale =
237	                            get_ptr<T>(scale_[i + 7 * layer_num_]);
238	                    }
239	                    else {
240	                        gpt_weights_.decoder_layer_weights[i]
241	                            ->after_attention_adapter_weights.intermediate_weight.scale =
242	                            get_ptr<float>(scale_[i + 4 * layer_num_]);
243	                        gpt_weights_.decoder_layer_weights[i]->after_attention_adapter_weights.output_weight.scale =
244	                            get_ptr<float>(scale_[i + 5 * layer_num_]);
245	                        gpt_weights_.decoder_layer_weights[i]->after_ffn_adapter_weights.intermediate_weight.scale =
246	                            get_ptr<float>(scale_[i + 6 * layer_num_]);
247	                        gpt_weights_.decoder_layer_weights[i]->after_ffn_adapter_weights.output_weight.scale =
248	                            get_ptr<float>(scale_[i + 7 * layer_num_]);
249	                    }
250	                }
251	            }
252	        }
253	
254	        int device_id = 0;
255	        ft::check_cuda_error(cudaGetDevice(&device_id));
256	        ft::check_cuda_error(cudaGetDeviceProperties(&prop_, device_id));
257	        FT_LOG_INFO("Device %s", prop_.name);
258	    }
259	
260	    ~FTGpt() override
261	    {
262	        ft::ftNcclParamDestroy(tensor_para_);
263	        ft::ftNcclParamDestroy(pipeline_para_);
264	        cublasLtDestroy(cublasltHandle_);
265	        delete cublas_algo_map_;
266	        delete cublas_wrapper_mutex_;
267	    }
268	
269	    void forward(th::Tensor&              input_ids,
270	                 th::Tensor&              input_lengths,
271	                 th::Tensor&              output_ids,
272	                 th::Tensor&              sequence_lengths,
273	                 th::Tensor&              cum_log_probs,
274	                 const size_t             request_output_len,
275	                 const size_t             beam_width,
276	                 th::optional<th::Tensor> top_k_opt,
277	                 th::optional<th::Tensor> top_p_opt,
278	                 th::optional<th::Tensor> beam_search_diversity_rate_opt,
279	                 th::optional<th::Tensor> temperature_opt,
280	                 th::optional<th::Tensor> len_penalty_opt,
281	                 th::optional<th::Tensor> repetition_penalty_opt,
282	                 th::optional<th::Tensor> presence_penalty_opt,
283	                 th::optional<th::Tensor> min_length_opt,
284	                 th::optional<th::Tensor> random_seed_opt,
285	                 th::optional<th::Tensor> bad_words_list_opt,
286	                 th::optional<int64_t>    return_cum_log_probs_opt) override
287	    {
288	        int  return_cum_log_probs   = return_cum_log_probs_opt.has_value() ? (int)return_cum_log_probs_opt.value() : 0;
289	        auto stream                 = at::cuda::getCurrentCUDAStream().stream();
290	        cublasHandle_t cublasHandle = at::cuda::getCurrentCUDABlasHandle();
291	        cublasSetStream(cublasHandle, stream);
292	        ft::Allocator<ft::AllocatorType::TH> allocator      = ft::Allocator<ft::AllocatorType::TH>();
293	        ft::cublasMMWrapper                  cublas_wrapper = ft::cublasMMWrapper(
294	            cublasHandle, cublasltHandle_, stream, cublas_algo_map_, cublas_wrapper_mutex_, &allocator);
295	
296	        if (std::is_same<T, half>::value) {
297	            cublas_wrapper.setGemmConfig(CUDA_R_16F, CUDA_R_16F, CUDA_R_16F, CUDA_R_32F);
298	        }
299	#ifdef ENABLE_BF16
300	        else if (std::is_same<T, __nv_bfloat16>::value) {
301	            cublas_wrapper.setBF16GemmConfig();
302	        }
303	#endif
304	        else if (std::is_same<T, float>::value) {
305	            cublas_wrapper.setFP32GemmConfig();
306	        }
307	
308	        const size_t request_batch_size = (size_t)input_ids.size(0);
309	        const size_t max_input_length   = (size_t)input_ids.size(1);
310	        const int    total_output_len   = (int)(max_input_length + request_output_len);
311	
312	        ft::AttentionType attention_type =
313	            ft::getAttentionType<T>(size_per_head_,
314	                                    ft::getSMVersion(),
315	                                    true,
316	                                    max_input_length,  // gpt supports any-seq-length fmha
317	                                    true,              // is_fuse
318	                                    false,             // with_relative_position_bias
319	                                    true);             // causal_mask
320	
321	        ft::ParallelGpt<T> gpt = ft::ParallelGpt<T>(request_batch_size,
322	                                                    total_output_len,
323	                                                    max_input_length,
324	                                                    beam_width,
325	                                                    head_num_,
326	                                                    size_per_head_,
327	                                                    inter_size_,
328	                                                    layer_num_,
329	                                                    expert_num_,
330	                                                    moe_k_,
331	                                                    moe_layer_index_,
332	                                                    vocab_size_,
333	                                                    start_id_,
334	                                                    end_id_,
335	                                                    end_id_ + 1,  // p/prompt tuning virtual token start id
336	                                                    ft::PromptLearningType::no_prompt,
337	                                                    gpt_variant_params_,
338	                                                    0.0f,  // beam_search_diversity_rate,
339	                                                    1,     // top_k,
340	                                                    0.0,   // top_p,
341	                                                    0,     // random_seed,
342	                                                    1.0f,  // temperature,
343	                                                    1.0f,  // len_penalty,
344	                                                    1.0f,  // repetition_penalty,
345	                                                    tensor_para_,
346	                                                    pipeline_para_,
347	                                                    stream,
348	                                                    &cublas_wrapper,
349	                                                    &allocator,
350	                                                    false,
351	                                                    &prop_,
352	                                                    attention_type,
353	                                                    false,
354	                                                    int8_mode_,
355	                                                    nullptr,
356	                                                    0,
357	                                                    shared_contexts_ratio_);
358	
359	        std::vector<uint32_t> output_seq_len(request_batch_size, total_output_len);
360	
361	        std::unordered_map<std::string, ft::Tensor> input_tensors = std::unordered_map<std::string, ft::Tensor>{
362	            {"input_ids",
363	             ft::Tensor{ft::MEMORY_GPU,
364	                        ft::TYPE_INT32,
365	                        std::vector<size_t>{request_batch_size, max_input_length},
366	                        get_ptr<int>(input_ids)}},
367	            {"input_lengths",
368	             ft::Tensor{
369	                 ft::MEMORY_GPU, ft::TYPE_INT32, std::vector<size_t>{request_batch_size}, get_ptr<int>(input_lengths)}},
370	            {"output_seq_len",
371	             ft::Tensor{
372	                 ft::MEMORY_CPU, ft::TYPE_UINT32, std::vector<size_t>{request_batch_size}, output_seq_len.data()}}};
373	        if (beam_width > 1 && beam_search_diversity_rate_opt.has_value()) {
374	            input_tensors.insert(
375	                {"beam_search_diversity_rate",
376	                 convert_tensor<float>(beam_search_diversity_rate_opt.value(), ft::MemoryType::MEMORY_CPU)});
377	        }
378	        if (top_p_opt.has_value()) {
379	            input_tensors.insert(
380	                {"runtime_top_p", convert_tensor<float>(top_p_opt.value(), ft::MemoryType::MEMORY_CPU)});
381	        }
382	        if (top_k_opt.has_value()) {
383	            input_tensors.insert(
384	                {"runtime_top_k", convert_tensor<uint>(top_k_opt.value(), ft::MemoryType::MEMORY_CPU)});
385	        }
386	        if (temperature_opt.has_value()) {
387	            input_tensors.insert(
388	                {"temperature", convert_tensor<float>(temperature_opt.value(), ft::MemoryType::MEMORY_CPU)});
389	        }
390	        if (len_penalty_opt.has_value()) {
391	            input_tensors.insert(
392	                {"len_penalty", convert_tensor<float>(len_penalty_opt.value(), ft::MemoryType::MEMORY_CPU)});
393	        }
394	        if (repetition_penalty_opt.has_value()) {
395	            input_tensors.insert({"repetition_penalty",
396	                                  convert_tensor<float>(repetition_penalty_opt.value(), ft::MemoryType::MEMORY_CPU)});
397	        }
398	        if (presence_penalty_opt.has_value()) {
399	            input_tensors.insert(
400	                {"presence_penalty", convert_tensor<float>(presence_penalty_opt.value(), ft::MemoryType::MEMORY_CPU)});
401	        }
402	        if (min_length_opt.has_value()) {
403	            input_tensors.insert(
404	                {"min_length", convert_tensor<int>(min_length_opt.value(), ft::MemoryType::MEMORY_CPU)});
405	        }
406	        if (random_seed_opt.has_value()) {
407	            input_tensors.insert(
408	                {"random_seed",
409	                 convert_tensor<unsigned long long int>(random_seed_opt.value(), ft::MemoryType::MEMORY_CPU)});
410	        }
411	
412	        if (bad_words_list_opt.has_value()) {
413	            CHECK_INPUT(bad_words_list_opt.value(), torch::kInt32);
414	            input_tensors.insert({"bad_words_list", convert_tensor<int>(bad_words_list_opt.value())});
415	        }
416	
417	        bool return_context_cum_log_probs = false;
418	        if (return_cum_log_probs == 2) {
419	            return_context_cum_log_probs = true;
420	            input_tensors.insert(
421	                {"is_return_context_cum_log_probs",
422	                 ft::Tensor{ft::MEMORY_CPU, ft::TYPE_BOOL, std::vector<size_t>{1}, &return_context_cum_log_probs}});
423	        }
424	
425	        std::unordered_map<std::string, ft::Tensor> output_tensors = std::unordered_map<std::string, ft::Tensor>{
426	            {"output_ids",
427	             ft::Tensor{ft::MEMORY_GPU,
428	                        ft::TYPE_INT32,
429	                        std::vector<size_t>{request_batch_size, beam_width, (size_t)total_output_len},
430	                        get_ptr<int>(output_ids)}},
431	            {"sequence_length",
432	             ft::Tensor{ft::MEMORY_GPU,
433	                        ft::TYPE_INT32,
434	                        std::vector<size_t>{request_batch_size, beam_width},
435	                        get_ptr<int>(sequence_lengths)}}};
436	
437	        if (return_cum_log_probs > 0) {
438	            output_tensors.insert({"cum_log_probs",
439	                                   ft::Tensor{ft::MEMORY_GPU,
440	                                              ft::TYPE_FP32,
441	                                              std::vector<size_t>{request_batch_size, beam_width},
442	                                              get_ptr<float>(cum_log_probs)}});
443	        }
444	
445	        try {
446	            gpt.forward(&output_tensors, &input_tensors, &gpt_weights_);
447	        }
448	        catch (const std::runtime_error& error) {
449	            FT_LOG_ERROR(error.what());
450	            ft::FT_CHECK(false);
451	        }
452	        catch (const std::exception& error) {
453	            FT_LOG_ERROR(error.what());
454	            ft::FT_CHECK(false);
455	        }
456	        catch (...) {
457	            FT_LOG_ERROR("Unknown error");
458	            ft::FT_CHECK(false);
459	        }
460	    }
461	
462	private:
463	    const int64_t        head_num_;
464	    const int64_t        size_per_head_;
465	    const int64_t        inter_size_;
466	    const int64_t        layer_num_;
467	    const int64_t        expert_num_;
468	    const int64_t        moe_k_;
469	    std::vector<int64_t> moe_layer_index_;
470	    const int64_t        vocab_size_;
471	    const int64_t        start_id_;
472	    const int64_t        end_id_;
473	    const double         shared_contexts_ratio_;
474	
475	    const int64_t int8_mode_ = 0;
476	
477	    int64_t tensor_para_size_;
478	    int64_t pipeline_para_size_;
479	
480	    ft::gptVariantParams gpt_variant_params_;
481	
482	    std::vector<th::Tensor> int8_weights_;
483	    std::vector<th::Tensor> scale_;
484	    std::vector<th::Tensor> weights_;
485	
486	    ft::NcclParam tensor_para_;
487	    ft::NcclParam pipeline_para_;
488	
489	    cublasLtHandle_t         cublasltHandle_;
490	    std::mutex*              cublas_wrapper_mutex_;
491	    ft::cublasAlgoMap*       cublas_algo_map_;
492	    struct cudaDeviceProp    prop_;
493	    ft::ParallelGptWeight<T> gpt_weights_;
494	    int                      world_size_ = 1;
495	    int                      rank_       = 0;
496	};
497	
