36	template<typename T>
37	class FTBert: public IFBert {
38	public:
39	    FTBert(size_t                         head_num,
40	           size_t                         head_size,
41	           size_t                         inter_size,
42	           size_t                         layer_num,
43	           bool                           sparse,
44	           float                          q_scaling,
45	           const size_t                   tensor_para_size,
46	           const size_t                   pipeline_para_size,
47	           const std::vector<th::Tensor>& w):
48	        _head_num(head_num),
49	        _head_size(head_size),
50	        _inter_size(inter_size),
51	        _layer_num(layer_num),
52	        _weights(w),
53	        _sparse(sparse),
54	        _q_scaling(q_scaling)
55	    {
56	#ifndef SPARSITY_ENABLED
57	        if (sparse) {
58	            std::cout << "[WARNING] Sparsity support is not enabled. Will use dense GEMM instead.\n" << std::flush;
59	        }
60	#endif
61	        ft::ftNcclInitialize(tensor_para_, pipeline_para_, tensor_para_size, pipeline_para_size);
62	        const int hidden_dim       = _head_num * _head_size;
63	        const int local_hidden_dim = (_head_num / tensor_para_.world_size_) * _head_size;
64	        ft::check_cuda_error(cublasLtCreate(&_cublasltHandle));
65	        sm_ = ft::getSMVersion();
66	#ifdef SPARSITY_ENABLED
67	        if (sparse) {
68	            CHECK_CUSPARSE(cusparseLtInit(&_cusparseLtHandle));
69	        }
70	#endif
71	        std::string sp_config_fname = sparse ? "spgemm_config.in" : "";
72	        cublas_algo_map_            = new ft::cublasAlgoMap("gemm_config.in", sp_config_fname);
73	        cublas_wrapper_mutex_       = new std::mutex();
74	
75	#ifdef LOAD_MODEL
76	        bert_weights = ft::BertWeight<T>(_head_num * _head_size,
77	                                         _inter_size,
78	                                         _layer_num,
79	                                         tensor_para_.world_size_,
80	                                         tensor_para_.rank_,
81	                                         pipeline_para_.world_size_,
82	                                         pipeline_para_.rank_);
83	        bert_weights.loadModel("tmp/" + std::to_string(tensor_para_.world_size_) + "-gpu/");
84	#else
