88	            int local_num_layer = (int)(ceil(_layer_num * 1.0f / pipeline_para_.world_size_));
89	            if (!(i < _layer_num && (i >= local_num_layer * pipeline_para_.rank_)
90	                  && (i < local_num_layer * (pipeline_para_.rank_ + 1)))) {
91	                continue;
92	            }
93	            const int first_layer_index = local_num_layer * pipeline_para_.rank_;
94	
95	            bert_weights.bert_layer_weights[i].attention_weights.query_weight.kernel =
96	                get_ptr<T>(_weights[0]) + hidden_dim * local_hidden_dim * (i - first_layer_index);
97	            bert_weights.bert_layer_weights[i].attention_weights.query_weight.bias =
98	                get_ptr<T>(_weights[1]) + local_hidden_dim * (i - first_layer_index);
99	            bert_weights.bert_layer_weights[i].attention_weights.key_weight.kernel =
100	                get_ptr<T>(_weights[2]) + hidden_dim * local_hidden_dim * (i - first_layer_index);
101	            bert_weights.bert_layer_weights[i].attention_weights.key_weight.bias =
102	                get_ptr<T>(_weights[3]) + local_hidden_dim * (i - first_layer_index);
103	            bert_weights.bert_layer_weights[i].attention_weights.value_weight.kernel =
104	                get_ptr<T>(_weights[4]) + hidden_dim * local_hidden_dim * (i - first_layer_index);
105	            bert_weights.bert_layer_weights[i].attention_weights.value_weight.bias =
106	                get_ptr<T>(_weights[5]) + local_hidden_dim * (i - first_layer_index);
107	            bert_weights.bert_layer_weights[i].attention_weights.attention_output_weight.kernel =
108	                get_ptr<T>(_weights[6]) + local_hidden_dim * hidden_dim * (i - first_layer_index);
109	            bert_weights.bert_layer_weights[i].attention_weights.attention_output_weight.bias =
110	                get_ptr<T>(_weights[7]) + hidden_dim * (i - first_layer_index);
111	            bert_weights.bert_layer_weights[i].attn_layernorm_weights.gamma =
112	                get_ptr<T>(_weights[8]) + hidden_dim * (i - first_layer_index);
113	            bert_weights.bert_layer_weights[i].attn_layernorm_weights.beta =
114	                get_ptr<T>(_weights[9]) + hidden_dim * (i - first_layer_index);
115	            bert_weights.bert_layer_weights[i].ffn_weights.intermediate_weight.kernel =
116	                get_ptr<T>(_weights[10])
117	                + hidden_dim * (_inter_size / tensor_para_.world_size_) * (i - first_layer_index);
118	            bert_weights.bert_layer_weights[i].ffn_weights.intermediate_weight.bias =
119	                get_ptr<T>(_weights[11]) + (_inter_size / tensor_para_.world_size_) * (i - first_layer_index);
120	            bert_weights.bert_layer_weights[i].ffn_weights.output_weight.kernel =
121	                get_ptr<T>(_weights[12])
122	                + (_inter_size / tensor_para_.world_size_) * hidden_dim * (i - first_layer_index);
123	            bert_weights.bert_layer_weights[i].ffn_weights.output_weight.bias =
124	                get_ptr<T>(_weights[13]) + hidden_dim * (i - first_layer_index);
125	            bert_weights.bert_layer_weights[i].ffn_layernorm_weights.gamma =
126	                get_ptr<T>(_weights[14]) + hidden_dim * (i - first_layer_index);
