135	            cublasHandle_t _cublasHandle = at::cuda::getCurrentCUDABlasHandle();
136	            cublasSetStream(_cublasHandle, stream);
137	            ft::cublasMMWrapper cublas_wrapper = ft::cublasMMWrapper(_cublasHandle,
