165	    void forward(size_t      batch_size,
166	                 size_t      seq_len,
167	                 th::Tensor& input,
168	                 th::Tensor& sequence_lengths,
169	                 th::Tensor& output,
170	                 bool        removing_padding) override
171	    {
172	        auto           stream        = at::cuda::getCurrentCUDAStream().stream();
173	        cublasHandle_t _cublasHandle = at::cuda::getCurrentCUDABlasHandle();
174	        cublasSetStream(_cublasHandle, stream);
175	        ft::Allocator<ft::AllocatorType::TH>* allocator = new ft::Allocator<ft::AllocatorType::TH>();
176	        ft::cublasMMWrapper*                  cublas_wrapper =
177	#ifdef SPARSITY_ENABLED
178	            new ft::cublasMMWrapper(_cublasHandle,
179	                                    _cublasltHandle,
180	                                    _cusparseLtHandle,
181	                                    stream,
182	                                    cublas_algo_map_,
183	                                    cublas_wrapper_mutex_,
184	                                    allocator);
185	#else
186	            new ft::cublasMMWrapper(
187	                _cublasHandle, _cublasltHandle, stream, cublas_algo_map_, cublas_wrapper_mutex_, allocator);
188	#endif
189	
190	        if (std::is_same<T, half>::value) {
191	            cublas_wrapper->setFP16GemmConfig();
192	        }
193	#ifdef ENABLE_BF16
194	        else if (std::is_same<T, __nv_bfloat16>::value) {
195	            cublas_wrapper->setBF16GemmConfig();
196	        }
197	#endif
198	        else if (std::is_same<T, float>::value) {
199	            cublas_wrapper->setFP32GemmConfig();
200	        }
201	
202	        ft::AttentionType attention_type = ft::getAttentionType<T>(_head_size, sm_, removing_padding, seq_len);
203	
204	        ft::Bert<T>* bert = new ft::Bert<T>(batch_size,
205	                                            seq_len,
206	                                            _head_num,
207	                                            _head_size,
208	                                            _inter_size,
209	                                            _layer_num,
210	                                            sm_,
211	                                            _q_scaling,
212	                                            stream,
213	                                            cublas_wrapper,
214	                                            allocator,
215	                                            true,
216	                                            attention_type,
217	                                            _sparse,
218	                                            ft::ActivationType::Gelu,
219	                                            ft::LayerNormType::post_layernorm,
220	                                            tensor_para_,
221	                                            pipeline_para_,
222	                                            nullptr,
223	                                            false);
224	
225	        ft::DataType            data_type     = ft::getTensorType<T>();
226	        std::vector<ft::Tensor> input_tensors = std::vector<ft::Tensor>{
227	            ft::Tensor{ft::MEMORY_GPU,
228	                       data_type,
229	                       std::vector<size_t>{batch_size, seq_len, (size_t)(_head_num * _head_size)},
230	                       get_ptr<T>(input)},
231	            ft::Tensor{
232	                ft::MEMORY_GPU, ft::TYPE_INT32, std::vector<size_t>{batch_size}, get_ptr<int>(sequence_lengths)}};
233	
234	        std::vector<ft::Tensor> output_tensors = std::vector<ft::Tensor>{
235	            ft::Tensor{ft::MEMORY_GPU,
236	                       data_type,
237	                       std::vector<size_t>{batch_size, seq_len, (size_t)(_head_num * _head_size)},
238	                       get_ptr<T>(output)}};
239	
240	        try {
241	            bert->forward(&output_tensors, &input_tensors, &bert_weights);
242	        }
243	        catch (std::runtime_error& error) {
244	            std::cout << error.what();
245	            exit(-1);
246	        }
247	        catch (...) {
248	            std::cout << "Runtime error";
249	            exit(-1);
250	        }
251	        delete bert;
252	        delete cublas_wrapper;
253	        delete allocator;
254	    }
